import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Admin = () => {
  const [clients, setClients] = useState([]);
  const [newClient, setNewClient] = useState({
    first_name: '',
    last_name: '',
    email: '',
    phone: '',
    password: '',
  });
  const [editingClient, setEditingClient] = useState(null);

  // Fetch clients from API
  useEffect(() => {
    axios.get('/api/clients')
      .then(response => setClients(response.data))
      .catch(err => console.error(err));
  }, []);

  // Handle form input change
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewClient({
      ...newClient,
      [name]: value,
    });
  };

  // Create a new client
  const handleCreateClient = (e) => {
    e.preventDefault();
    axios.post('/api/clients_create', newClient)
      .then(response => {
        setClients([...clients, response.data]);
        setNewClient({
          first_name: '',
          last_name: '',
          email: '',
          phone: '',
          password: '',
        });
      })
      .catch(err => console.error(err));
  };

  // Handle editing an existing client
  const handleEditClient = (client) => {
    setEditingClient(client);
    setNewClient(client);
  };

  // Handle updating an existing client
  const handleUpdateClient = (e) => {
    e.preventDefault();
    axios.put(`/api/clients_put${editingClient.id}`, newClient)
      .then(response => {
        setClients(clients.map(client => client.id === editingClient.id ? response.data : client));
        setEditingClient(null);
        setNewClient({
          first_name: '',
          last_name: '',
          email: '',
          phone: '',
          password: '',
        });
      })
      .catch(err => console.error(err));
  };

  // Handle deleting a client
  const handleDeleteClient = (id) => {
    axios.delete(`/api/clients_del${id}`)
      .then(() => setClients(clients.filter(client => client.id !== id)))
      .catch(err => console.error(err));
  };

  return (
    <div className="container">
      <div className="card">
        <h2>{editingClient ? 'Edit Client' : 'Create Client'}</h2>
        <form onSubmit={editingClient ? handleUpdateClient : handleCreateClient}>
          <div className="form-container">
            <div className="form-outline">
              <label>First Name</label>
              <input
                type="text"
                name="first_name"
                value={newClient.first_name}
                onChange={handleInputChange}
                placeholder="First Name"
              />
            </div>
            <div className="form-outline">
              <label>Last Name</label>
              <input
                type="text"
                name="last_name"
                value={newClient.last_name}
                onChange={handleInputChange}
                placeholder="Last Name"
              />
            </div>
            <div className="form-outline">
              <label>Email</label>
              <input
                type="email"
                name="email"
                value={newClient.email}
                onChange={handleInputChange}
                placeholder="Email"
              />
            </div>
            <div className="form-outline">
              <label>Phone</label>
              <input
                type="text"
                name="phone"
                value={newClient.phone}
                onChange={handleInputChange}
                placeholder="Phone"
              />
            </div>
            <div className="form-outline">
              <label>Password</label>
              <input
                type="password"
                name="password"
                value={newClient.password}
                onChange={handleInputChange}
                placeholder="Password"
              />
            </div>
            <button type="submit" className="btn">
              {editingClient ? 'Update Client' : 'Create Client'}
            </button>
          </div>
        </form>

        <h3>Clients List</h3>
        <table>
          <thead>
            <tr>
              <th>First Name</th>
              <th>Last Name</th>
              <th>Email</th>
              <th>Phone</th>
              <th>Password Hash</th>
              <th>Is Admin</th>
              <th>Is Manager</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {clients.map(client => (
              <tr key={client.id}>
                <td>{client.first_name}</td>
                <td>{client.last_name}</td>
                <td>{client.email}</td>
                <td>{client.phone}</td>
                <td>{client.password_hash}</td>
                <td>{client.is_admin ? 'Yes' : 'No'}</td>
                <td>{client.is_manager ? 'Yes' : 'No'}</td>
                <td>
                  <button onClick={() => handleEditClient(client)}>Edit</button>
                  <button onClick={() => handleDeleteClient(client.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Admin;
